        forceRefresh() { this._forceRefresh = true; this._cachedContext = null; },
        getChat() { return this.getContext()?.chat || []; },
        getChatLength() { return this.getChat().length; },
        getCurrentSwipeId() { const chat = this.getChat(); if (!chat.length) return null; const lastMsg = chat[chat.length - 1]; if (!lastMsg) return null; const swipeIdx = lastMsg.swipe_id ?? 0; const swipes = lastMsg.swipes; const swipeContent = swipes?.[swipeIdx]?.mes || lastMsg.mes || ''; return `${chat.length}-${swipeIdx}-${swipeContent.slice(0, 50)}`; },
        checkSwipeChange() { const currentId = this.getCurrentSwipeId(); const changed = this._lastSwipeId !== null && currentId !== this._lastSwipeId; this._lastSwipeId = currentId; return changed; },
        checkChatLengthChange() { const currentLen = this.getChatLength(); const changed = this._lastChatLength !== 0 && currentLen !== this._lastChatLength; this._lastChatLength = currentLen; return changed; },
        getLatestUserMsgIndex() { const chat = this.getChat(); for (let i = chat.length - 1; i >= 0; i--) { if (chat[i].is_user) return i; } return -1; },
        findMsgIndex(txt) { const chat = this.getChat(); if (!chat.length || !txt) return -1; const lines = txt.split('\n'); let feature = ''; for (const l of lines) { const t = l.trim(); if (t.length >= 2) { feature = t; break; } } if (!feature) feature = txt.replace(/[\n\r\s]+/g, ' ').trim().slice(0, 50); if (!feature || feature.length < 2) return -1; for (let i = chat.length - 1; i >= 0; i--) { if (chat[i].is_user && (chat[i].mes || '').includes(feature)) return i; } return -1; },
        getQrfFromIndex(idx) { const chat = this.getChat(); if (idx < 0 || idx >= chat.length) return ''; return chat[idx].extra?.qrf_plot || chat[idx].qrf_plot || ''; },
        getFromIndex(idx, tag) { const qrf = this.getQrfFromIndex(idx); const m = qrf.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'i')); return m ? m[1].trim() : ''; },
        getFileFromFloorRange(maxIdx) {
            const chat = this.getChat();
            const regex = /<file[^>]*>([\s\S]*?)<\/file>/i;
            for (let i = Math.min(maxIdx, chat.length - 1); i >= 0; i--) {
                const msg = chat[i];
                if (!msg) continue;
                const sources = [msg.extra?.qrf_plot, msg.qrf_plot];
                if (msg.swipes && Array.isArray(msg.swipes)) {
                    for (const swipe of msg.swipes) {
                        if (swipe?.extra?.qrf_plot) sources.push(swipe.extra.qrf_plot);
                    }
                }
                for (const src of sources.filter(Boolean)) {
                    const match = src.match(regex);
                    if (match && match[1] && match[1].length > 50) {
                        return { idx: i, content: match[1].trim() };
                    }
                }
            }
            return { idx: -1, content: '' };
