        getReviewsFromIndex(idx) { const qrf = this.getQrfFromIndex(idx); const results = []; const regex = /<review\s+npc=['"]([^'"]+)['"][^>]*>([\s\S]*?)<\/review>/gi; let m; while ((m = regex.exec(qrf)) !== null) results.push({ npc: m[1], content: m[2].trim() }); return results; },
        getRecentReviews(count = 10) { const chat = this.getChat(); const results = []; const regex = /<review\s+npc=['"]([^'"]+)['"][^>]*>([\s\S]*?)<\/review>/gi; for (let i = chat.length - 1; i >= Math.max(0, chat.length - count); i--) { const msg = chat[i]; const sources = [msg.extra?.qrf_plot, msg.qrf_plot].filter(Boolean); for (const src of sources) { let m; while ((m = regex.exec(src)) !== null) { if (!results.find(r => r.npc === m[1])) results.push({ npc: m[1], content: m[2].trim() }); } regex.lastIndex = 0; } if (results.length > 0) break; } return results; },
        getUserInput() { const chat = this.getChat(); for (let i = chat.length - 1; i >= 0; i--) { if (chat[i].is_user) return chat[i].mes || ''; } return ''; },
        extractTag(tag, opts = {}) { const { count = 10, all = false } = opts; const chat = this.getChat(); if (!chat.length) return all ? [] : ''; const regex = new RegExp(`<${tag}(?:\\s[^>]*)?>[\\s\\S]*?<\\/${tag}>`, 'gi'); const results = []; const limit = Math.max(0, chat.length - count); for (let i = chat.length - 1; i >= limit; i--) { const msg = chat[i]; const sources = [msg.mes, msg.extra?.qrf_plot, msg.qrf_plot].filter(Boolean); for (const src of sources) { let m; while ((m = regex.exec(src)) !== null) { const inner = m[0].replace(new RegExp(`^<${tag}[^>]*>|<\\/${tag}>$`, 'gi'), '').trim(); results.push({ content: inner, fullMatch: m[0], msgIndex: i }); if (!all) return inner; } regex.lastIndex = 0; } } return all ? results : ''; },
        countNpcAppearances() { const chat = this.getChat(); const counts = {}; const regex = /<!--(?:登场)?NPC=['"]([^'"]+)['"]/gi; for (const msg of chat) { const sources = [msg.mes, msg.extra?.qrf_plot, msg.qrf_plot].filter(Boolean); for (const src of sources) { let m; while ((m = regex.exec(src)) !== null) { const name = m[1].trim(); if (!isUserName(name)) counts[name] = (counts[name] || 0) + 1; } regex.lastIndex = 0; } } return counts; }
    };

