 fa-sliders"></i> 更多设置</div></div></div>${archiveHtml}<div class="card ${cardClosed}"><div class="card-header"><div class="title"><i class="fa-solid fa-code"></i> 原始数据</div><i class="fa-solid fa-chevron-down chevron"></i></div><div class="card-body"><div class="raw-toggle" id="raw-toggle">${rawData}</div><div class="raw-box" id="raw-box">${(this.displayFile + '\n\n' + this.displayScene).replace(/</g, '&lt;').replace(/>/g, '&gt;')}</div></div></div>`; page.querySelectorAll('.card-header').forEach(hdr => { hdr.addEventListener('click', () => hdr.closest('.card').classList.toggle('closed')); }); page.querySelectorAll('.theme-dot').forEach(dot => { dot.addEventListener('click', () => { this.setTheme(dot.dataset.theme); page.querySelectorAll('.theme-dot').forEach(d => d.classList.remove('active')); dot.classList.add('active'); }); }); $('set-btn')?.addEventListener('click', () => this.toggleSettings()); $('raw-toggle')?.addEventListener('click', () => $('raw-box').classList.toggle('show')); page.querySelectorAll('.file-item-hdr').forEach(hdr => { hdr.addEventListener('click', () => hdr.closest('.file-item').classList.toggle('open')); }); },

        toggleFav(n) { if (this.d.favs.includes(n)) this.d.favs = this.d.favs.filter(x => x !== n); else this.d.favs.push(n); this.save(); this.parse(); },
        setTheme(t) { this.d.theme = t; $('app').dataset.theme = t; $('cfg-theme').value = t; this.save(); },
        toggleSettings() { $('settings').classList.toggle('on'); },
